local xml = require("xml")
local ltn12 = require("ltn12")
local cjson = cjson or require("cjson")

function read_body(src)
  local chunks = {}
  for chunk in src:gmatch(".*\r\n(?:[\w-]+: )?([^\r\n]*)\r\n*") do
    table.insert(chunks, chunk)
  end
  return table.concat(chunks, ltn12.null)
end

function on_body(self)
  local body = read_body(self.req)
  local doc = xml.parse(body)

  -- Extract data from parsed XML for processing
  for _, elem in ipairs(doc:getChildrenByTagName("your_tag")) do
    local data = {}
    for _, attr in ipairs(elem:getAttributes()) do
      table.insert(data, {name=attr:getName(), value=attr:getValue()})
    end
    for _, child in ipairs(elem:getChildren()) do
      table.insert(data, {name=child:getName(), value=child:getText()})
    end

    -- Process the extracted data as needed
    print(cjson.encode(data))
  end
end

